/**
 * station-ws.test.ts — verify WSStation construction, frame encoding,
 * and IStation surface parity with HTTPS Station.
 *
 * We stub `globalThis.WebSocket` with a loopback fake that pipes encoded
 * frames through a FlowCodec on the "server" side and emits a FIN frame
 * back so the WSStation's `forward()` resolves with deterministic bytes.
 *
 * What this test verifies (per wave-19 wiring task):
 *   1. Construct WSStation from config (rejects malformed config).
 *   2. forward() sends a PHASE_{A,B,C} frame on stream STREAM_SPLIT_*_BASE
 *      + startLayer with the correct startPos / seqLen prefix.
 *   3. Response shape matches HTTPS Station: `{ residual: Float32Array }`.
 *   4. Falls back to HTTPS Station for embed / lmHead / cobordism methods
 *      (sanity check that the unimplemented /flow methods don't throw at
 *      the WSStation surface).
 *
 * NOT covered (would need a real worker): wire-level latency comparison,
 * cosine parity vs real kernel output. The wave-18 bench
 * (scripts/bench-death3-3worker.ts) covers those against the live mesh.
 */

import { afterEach, beforeEach, describe, expect, it } from 'vitest';

import {
  FlowCodec,
  PHASE_A,
  PHASE_B,
  PHASE_C,
  STREAM_SPLIT_A_BASE,
  STREAM_SPLIT_B_BASE,
  STREAM_SPLIT_C_BASE,
  decodeInferencePrefix,
  splitFlowFrameBatch,
} from '@a0n/aeon/flow';

import { WSStation } from '../src/station-ws';

const HIDDEN_DIM = 4;

// ── Fake WebSocket loopback ───────────────────────────────────────────
// Stub installed on globalThis.WebSocket. Captures every frame the
// WSStation sends, decodes it, and emits a FIN frame back with a
// deterministic body the test inspects.

interface CapturedFrame {
  streamId: number;
  sequence: number;
  flags: number;
  startPos: number;
  seqLen: number;
  body: Uint8Array;
}

class FakeWebSocket {
  static lastInstance: FakeWebSocket | null = null;
  static lastUrl = '';
  static replyForFrame:
    | ((f: CapturedFrame) => { ok: true; payload: Uint8Array } | { ok: false; error: string })
    | null = null;

  binaryType = 'arraybuffer';
  readyState = 0;
  url: string;
  captured: CapturedFrame[] = [];
  /**
   * Number of underlying `send()` invocations (one per WS write). Coalesced
   * frames arrive in a single `send()` call carrying multiple flow frames,
   * so `sendCallCount` < `captured.length` is the signature of a coalesce.
   */
  sendCallCount = 0;
  private listeners = new Map<string, Array<(evt: { data?: unknown }) => void>>();
  private codec: FlowCodec | null = null;

  constructor(url: string, _opts?: unknown) {
    this.url = url;
    FakeWebSocket.lastUrl = url;
    FakeWebSocket.lastInstance = this;
    // Async-resolve: first FlowCodec.create, then fire 'open' on next tick.
    void FlowCodec.create({ wasmMode: 'off' }).then((codec) => {
      this.codec = codec;
      this.readyState = 1;
      queueMicrotask(() => this.dispatch('open'));
    });
  }

  addEventListener(
    type: string,
    handler: (evt: { data?: unknown }) => void,
    _opts?: unknown,
  ): void {
    let bucket = this.listeners.get(type);
    if (!bucket) {
      bucket = [];
      this.listeners.set(type, bucket);
    }
    bucket.push(handler);
  }

  send(data: ArrayBuffer | ArrayBufferView): void {
    const bytes =
      data instanceof ArrayBuffer
        ? new Uint8Array(data)
        : new Uint8Array(
            (data as ArrayBufferView).buffer,
            (data as ArrayBufferView).byteOffset,
            (data as ArrayBufferView).byteLength,
          );
    if (!this.codec) throw new Error('FakeWebSocket: codec not ready');
    this.sendCallCount++;

    // Coalesced sends arrive as N concatenated flow frames in one buffer.
    // splitFlowFrameBatch returns false for non-flow data; if it returns
    // false we fall back to single-frame decode (preserves pre-coalesce
    // behaviour for tests that disable batching).
    const frameBuffers: Uint8Array[] = [];
    const isBatch = splitFlowFrameBatch(bytes, (f) => {
      // Copy out of the shared buffer so async reply scheduling cannot
      // alias bytes when the next send() arrives.
      frameBuffers.push(new Uint8Array(f));
    });
    if (!isBatch) {
      frameBuffers.push(bytes);
    }

    for (const frameBytes of frameBuffers) {
      const codec = this.codec;
      const tick = codec.decode(frameBytes).frame;
      const prefix = decodeInferencePrefix(tick.payload);
      const captured: CapturedFrame = {
        streamId: tick.streamId,
        sequence: tick.sequence,
        flags: tick.flags,
        startPos: prefix.startPos,
        seqLen: prefix.seqLen,
        body: prefix.body,
      };
      this.captured.push(captured);

      // Build the response per the test's installed reply-fn.
      const reply = FakeWebSocket.replyForFrame
        ? FakeWebSocket.replyForFrame(captured)
        : { ok: true as const, payload: new Uint8Array(0) };

      const flags = reply.ok ? 0x10 /* FIN */ : 0x08 /* VENT */;
      const payload = reply.ok ? reply.payload : new TextEncoder().encode(reply.error);

      const replyFrame = codec.encode({
        streamId: captured.streamId,
        sequence: captured.sequence,
        flags,
        payload,
      });
      const replyBuf = replyFrame.buffer.slice(
        replyFrame.byteOffset,
        replyFrame.byteOffset + replyFrame.byteLength,
      );
      queueMicrotask(() => this.dispatch('message', { data: replyBuf }));
    }
  }

  close(): void {
    this.readyState = 3;
    queueMicrotask(() => this.dispatch('close'));
  }

  private dispatch(type: string, evt?: { data?: unknown }): void {
    const bucket = this.listeners.get(type);
    if (!bucket) return;
    for (const fn of bucket) {
      try { fn(evt ?? {}); } catch { /* swallow in test fake */ }
    }
  }
}

const realWebSocket = (globalThis as { WebSocket?: unknown }).WebSocket;

beforeEach(() => {
  (globalThis as unknown as { WebSocket: typeof FakeWebSocket }).WebSocket =
    FakeWebSocket;
  FakeWebSocket.lastInstance = null;
  FakeWebSocket.lastUrl = '';
  FakeWebSocket.replyForFrame = null;
});

afterEach(() => {
  if (realWebSocket === undefined) {
    delete (globalThis as { WebSocket?: unknown }).WebSocket;
  } else {
    (globalThis as { WebSocket?: unknown }).WebSocket = realWebSocket;
  }
});

describe('WSStation', () => {
  it('rejects construction without a phase', () => {
    expect(() =>
      new WSStation({
        endpoint: 'https://example.com',
        startLayer: 0,
        endLayer: 1,
      } as unknown as ConstructorParameters<typeof WSStation>[0]),
    ).toThrow(/phase/);
  });

  it('rejects non-string endpoints', () => {
    expect(() =>
      new WSStation({
        endpoint: { fetch: async () => new Response() },
        startLayer: 0,
        endLayer: 1,
        phase: 'split-a',
      } as unknown as ConstructorParameters<typeof WSStation>[0]),
    ).toThrow(/endpoint/);
  });

  it('rejects malformed layer range', () => {
    expect(() =>
      new WSStation({
        endpoint: 'https://example.com',
        startLayer: 5,
        endLayer: 5,
        phase: 'split-a',
      }),
    ).toThrow(/endLayer/);
  });

  it('opens a wss:// socket and translates https:// in the URL', async () => {
    const station = new WSStation({
      endpoint: 'https://tri-g4-a-00.example.com',
      startLayer: 7,
      endLayer: 8,
      phase: 'split-a',
    });
    FakeWebSocket.replyForFrame = (f) => ({
      ok: true,
      payload: floatsToBytes(new Float32Array(2 * HIDDEN_DIM * f.seqLen)),
    });
    await station.forward({
      residual: new Float32Array(HIDDEN_DIM),
      startPos: 0,
      sequenceLength: 1,
    });
    expect(FakeWebSocket.lastUrl).toBe('wss://tri-g4-a-00.example.com/flow');
    station.close();
  });

  it('forwards a PHASE_A frame on stream STREAM_SPLIT_A_BASE+startLayer', async () => {
    const station = new WSStation({
      endpoint: 'https://example.com',
      startLayer: 3,
      endLayer: 4,
      phase: 'split-a',
    });
    const replyBody = floatsToBytes(new Float32Array(2 * HIDDEN_DIM));
    FakeWebSocket.replyForFrame = () => ({ ok: true, payload: replyBody });

    const residual = new Float32Array(HIDDEN_DIM);
    for (let i = 0; i < HIDDEN_DIM; i++) residual[i] = (i + 1) * 0.01;
    const out = await station.forward({
      residual,
      startPos: 11,
      sequenceLength: 1,
    });

    const frame = FakeWebSocket.lastInstance!.captured[0]!;
    expect(frame.streamId).toBe(STREAM_SPLIT_A_BASE + 3);
    expect(frame.flags).toBe(PHASE_A);
    expect(frame.startPos).toBe(11);
    expect(frame.seqLen).toBe(1);
    // body bytes match what we sent
    const sentFloats = new Float32Array(frame.body.buffer.slice(frame.body.byteOffset, frame.body.byteOffset + frame.body.byteLength));
    expect(Array.from(sentFloats)).toEqual(Array.from(residual));

    // Response shape mirrors HTTPS Station: `{ residual: Float32Array }`
    expect(out).toHaveProperty('residual');
    expect(out.residual).toBeInstanceOf(Float32Array);
    expect(out.residual.length).toBe(2 * HIDDEN_DIM);
    station.close();
  });

  it('uses STREAM_SPLIT_B_BASE / PHASE_B for split-b phase', async () => {
    const station = new WSStation({
      endpoint: 'https://example.com',
      startLayer: 5,
      endLayer: 6,
      phase: 'split-b',
    });
    FakeWebSocket.replyForFrame = () => ({
      ok: true,
      payload: floatsToBytes(new Float32Array(4 * HIDDEN_DIM)),
    });
    await station.forward({
      residual: new Float32Array(HIDDEN_DIM),
      startPos: 0,
      sequenceLength: 1,
    });
    const frame = FakeWebSocket.lastInstance!.captured[0]!;
    expect(frame.streamId).toBe(STREAM_SPLIT_B_BASE + 5);
    expect(frame.flags).toBe(PHASE_B);
    station.close();
  });

  it('uses STREAM_SPLIT_C_BASE / PHASE_C for split-c phase', async () => {
    const station = new WSStation({
      endpoint: 'https://example.com',
      startLayer: 9,
      endLayer: 10,
      phase: 'split-c',
    });
    FakeWebSocket.replyForFrame = () => ({
      ok: true,
      payload: floatsToBytes(new Float32Array(HIDDEN_DIM)),
    });
    await station.forward({
      residual: new Float32Array(HIDDEN_DIM * 2),
      startPos: 0,
      sequenceLength: 1,
    });
    const frame = FakeWebSocket.lastInstance!.captured[0]!;
    expect(frame.streamId).toBe(STREAM_SPLIT_C_BASE + 9);
    expect(frame.flags).toBe(PHASE_C);
    station.close();
  });

  it('reuses one socket across N forward() calls (persistent)', async () => {
    const station = new WSStation({
      endpoint: 'https://example.com',
      startLayer: 0,
      endLayer: 1,
      phase: 'split-a',
    });
    FakeWebSocket.replyForFrame = () => ({
      ok: true,
      payload: floatsToBytes(new Float32Array(2 * HIDDEN_DIM)),
    });
    for (let i = 0; i < 5; i++) {
      await station.forward({
        residual: new Float32Array(HIDDEN_DIM),
        startPos: i,
        sequenceLength: 1,
      });
    }
    const inst = FakeWebSocket.lastInstance!;
    expect(inst.captured.length).toBe(5);
    // Sequence numbers strictly increase, proving one socket served all five.
    const seqs = inst.captured.map((f) => f.sequence);
    expect(seqs).toEqual([1, 2, 3, 4, 5]);
    station.close();
  });

  it('surfaces a VENT response as a forward() error', async () => {
    const station = new WSStation({
      endpoint: 'https://example.com',
      startLayer: 0,
      endLayer: 1,
      phase: 'split-a',
    });
    FakeWebSocket.replyForFrame = () => ({ ok: false, error: 'kernel boom' });
    await expect(
      station.forward({
        residual: new Float32Array(HIDDEN_DIM),
        startPos: 0,
        sequenceLength: 1,
      }),
    ).rejects.toThrow(/kernel boom/);
    station.close();
  });

  it('rejects forward() with negative startPos', async () => {
    const station = new WSStation({
      endpoint: 'https://example.com',
      startLayer: 0,
      endLayer: 1,
      phase: 'split-a',
    });
    await expect(
      station.forward({
        residual: new Float32Array(HIDDEN_DIM),
        startPos: -1,
        sequenceLength: 1,
      }),
    ).rejects.toThrow(/startPos/);
    station.close();
  });

  // ── Leg 1 — frame coalescing (TOPOLOGY_CEILING_BREAKERS §4) ──────────
  // Two send paths in the same microtask should ride one underlying
  // socket.send() when GNOSIS_FRAME_COALESCE is on (default), and
  // separate writes when disabled. The fake WS tracks `sendCallCount`
  // (per-write) vs `captured.length` (per-frame); coalescing means
  // sendCallCount < captured.length.
  describe('frame_coalescing_combines_same_turn_sends', () => {
    const prior = process.env['GNOSIS_FRAME_COALESCE'];
    afterEach(() => {
      if (prior === undefined) delete process.env['GNOSIS_FRAME_COALESCE'];
      else process.env['GNOSIS_FRAME_COALESCE'] = prior;
    });

    it('coalesces two same-microtask forwards into ONE socket.send (default ON)', async () => {
      delete process.env['GNOSIS_FRAME_COALESCE'];
      const station = new WSStation({
        endpoint: 'https://example.com',
        startLayer: 0,
        endLayer: 1,
        phase: 'split-a',
      });
      FakeWebSocket.replyForFrame = () => ({
        ok: true,
        payload: floatsToBytes(new Float32Array(2 * HIDDEN_DIM)),
      });

      // Warm the socket so the FakeWebSocket.codec is ready and the
      // FlowSendBatcher is constructed; the second pair of calls is the
      // one we measure for coalescing.
      await station.forward({
        residual: new Float32Array(HIDDEN_DIM),
        startPos: 0,
        sequenceLength: 1,
      });
      const inst = FakeWebSocket.lastInstance!;
      const sendsBefore = inst.sendCallCount;
      const framesBefore = inst.captured.length;

      // Two forward() calls without await between → both queued in same
      // microtask → batcher flushes both as ONE socket.send().
      const p1 = station.forward({
        residual: new Float32Array(HIDDEN_DIM),
        startPos: 1,
        sequenceLength: 1,
      });
      const p2 = station.forward({
        residual: new Float32Array(HIDDEN_DIM),
        startPos: 2,
        sequenceLength: 1,
      });
      await Promise.all([p1, p2]);

      const sendsAfter = inst.sendCallCount;
      const framesAfter = inst.captured.length;
      expect(framesAfter - framesBefore).toBe(2);
      expect(sendsAfter - sendsBefore).toBe(1);
      station.close();
    });

    it('does NOT coalesce when GNOSIS_FRAME_COALESCE=0', async () => {
      process.env['GNOSIS_FRAME_COALESCE'] = '0';
      const station = new WSStation({
        endpoint: 'https://example.com',
        startLayer: 0,
        endLayer: 1,
        phase: 'split-a',
      });
      FakeWebSocket.replyForFrame = () => ({
        ok: true,
        payload: floatsToBytes(new Float32Array(2 * HIDDEN_DIM)),
      });

      // Warm the socket.
      await station.forward({
        residual: new Float32Array(HIDDEN_DIM),
        startPos: 0,
        sequenceLength: 1,
      });
      const inst = FakeWebSocket.lastInstance!;
      const sendsBefore = inst.sendCallCount;
      const framesBefore = inst.captured.length;

      const p1 = station.forward({
        residual: new Float32Array(HIDDEN_DIM),
        startPos: 1,
        sequenceLength: 1,
      });
      const p2 = station.forward({
        residual: new Float32Array(HIDDEN_DIM),
        startPos: 2,
        sequenceLength: 1,
      });
      await Promise.all([p1, p2]);

      const sendsAfter = inst.sendCallCount;
      const framesAfter = inst.captured.length;
      expect(framesAfter - framesBefore).toBe(2);
      // No coalescing → one write per frame.
      expect(sendsAfter - sendsBefore).toBe(2);
      station.close();
    });

    it('also disables coalescing when GNOSIS_FRAME_COALESCE=false (case-insensitive)', async () => {
      process.env['GNOSIS_FRAME_COALESCE'] = 'FALSE';
      const station = new WSStation({
        endpoint: 'https://example.com',
        startLayer: 0,
        endLayer: 1,
        phase: 'split-a',
      });
      FakeWebSocket.replyForFrame = () => ({
        ok: true,
        payload: floatsToBytes(new Float32Array(2 * HIDDEN_DIM)),
      });

      await station.forward({
        residual: new Float32Array(HIDDEN_DIM),
        startPos: 0,
        sequenceLength: 1,
      });
      const inst = FakeWebSocket.lastInstance!;
      const sendsBefore = inst.sendCallCount;

      const p1 = station.forward({
        residual: new Float32Array(HIDDEN_DIM),
        startPos: 1,
        sequenceLength: 1,
      });
      const p2 = station.forward({
        residual: new Float32Array(HIDDEN_DIM),
        startPos: 2,
        sequenceLength: 1,
      });
      await Promise.all([p1, p2]);

      expect(inst.sendCallCount - sendsBefore).toBe(2);
      station.close();
    });
  });
});

// ── helpers ────────────────────────────────────────────────────────────

function floatsToBytes(arr: Float32Array): Uint8Array {
  return new Uint8Array(arr.buffer.slice(arr.byteOffset, arr.byteOffset + arr.byteLength));
}
